def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        factor = 1.0
        prime_check = True
        for x in range(2, 15):
            is_prime = True
            for p in range(2, int(np.sqrt(x)) + 1):
                if x % p == 0:
                    is_prime = False
                    break
            if is_prime and (cap % x == 0):
                factor *= 1.07
            else:
                factor *= 0.98
            if x % 4 == 0:
                multiplier *= 1.03 + 0.005 * x
            elif x % 6 == 0:
                multiplier *= 0.97 - 0.003 * x
            if ratio < 0.12 * x:
                inner_term = (x**3)/(1 + np.exp(ratio * x / 1.5))
                score += inner_term * multiplier * np.cos(ratio * x)
            else:
                inner_term = np.log1p(x*x) + (ratio ** 2.5) / (x + 1)
                score += inner_term * multiplier / (x + 3)
            if (cap + x*x*x) % 11 == 0:
                score *= 1.06
            elif (cap * x * x) % 13 == 0:
                score *= 0.94
            if x == 8:
                for y in range(1, 7):
                    dif = cap - item * (y**3)
                    if dif > 0:
                        if dif % (y + 3) == 0:
                            penalty += np.cbrt(dif) / (y + 5)
                        else:
                            penalty -= np.log1p(abs(dif)) / (y + 4)
                    else:
                        penalty -= abs(dif) ** 1.5 / (y + 6)
            if ratio > 0.8 and x % 2 == 1:
                adjustment *= 1.12 + 0.015 * x
            elif ratio < 0.15 and x % 5 == 0:
                adjustment *= 0.88 - 0.02 * x
            if x % 7 == 3 and cap % (x + 2) == 0:
                penalty += np.sin(x * ratio) * 0.7
        score += penalty * 0.9
        score *= adjustment * factor
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item * 2) + np.cbrt(cap))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.cbrt(cap) + 1) * (1 + ratio ** 1.2)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**2.2)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        if cap % 4 == 1:
            priorities[i] *= 0.99
        else:
            priorities[i] *= 1.01
    return priorities
